import { InboundPolicyHandler, ZuploContext, ZuploRequest } from "@zuplo/runtime";

interface CorsInboundOptions {
  allowedOrigins: string[]; // placeholder, actual origin is computed from env
  allowedMethods: string[];
  allowedHeaders: string[];
}

export const CorsInboundPolicy: InboundPolicyHandler<CorsInboundOptions> = async (
  request: ZuploRequest,
  context: ZuploContext,
  options: CorsInboundOptions,
  policyName: string
) => {
  const runId = process.env.ZEALT_RUN_ID || "";
  const allowedOrigin = `https://example-${runId}.com`;

  const origin = request.headers.get("Origin") || "";

  // Handle OPTIONS preflight request
  if (request.method === "OPTIONS") {
    if (origin === allowedOrigin) {
      return new Response(null, {
        status: 204,
        headers: {
          "Access-Control-Allow-Origin": allowedOrigin,
          "Access-Control-Allow-Methods": options.allowedMethods.join(", "),
          "Access-Control-Allow-Headers": options.allowedHeaders.join(", "),
          "Access-Control-Max-Age": "86400",
        },
      });
    }
    // Origin not allowed - still return 204 but without CORS headers
    return new Response(null, { status: 204 });
  }

  // For non-OPTIONS requests, store the allowed origin in context for the outbound policy
  context.customData.__corsAllowedOrigin = origin === allowedOrigin ? allowedOrigin : null;
  context.customData.__corsAllowedMethods = options.allowedMethods;
  context.customData.__corsAllowedHeaders = options.allowedHeaders;

  return request;
};

import { OutboundPolicyHandler, ZuploContext, ZuploRequest } from "@zuplo/runtime";

interface CorsOutboundOptions {
  allowedMethods: string[];
  allowedHeaders: string[];
}

export const CorsOutboundPolicy: OutboundPolicyHandler<CorsOutboundOptions> = async (
  response: Response,
  request: ZuploRequest,
  context: ZuploContext,
  options: CorsOutboundOptions,
  policyName: string
) => {
  const runId = process.env.ZEALT_RUN_ID || "";
  const allowedOrigin = `https://example-${runId}.com`;

  const origin = request.headers.get("Origin") || "";

  // Only add CORS headers if the origin matches the allowed origin
  if (origin !== allowedOrigin) {
    return response;
  }

  const newResponse = new Response(response.body, response);
  newResponse.headers.set("Access-Control-Allow-Origin", allowedOrigin);
  newResponse.headers.set("Access-Control-Allow-Methods", options.allowedMethods.join(", "));
  newResponse.headers.set("Access-Control-Allow-Headers", options.allowedHeaders.join(", "));

  return newResponse;
};

import { ZuploContext, ZuploRequest } from "@zuplo/runtime";

export default async function (request: ZuploRequest, context: ZuploContext) {
  return Response.json({ message: "Hello CORS" });
}

